// Msgsize returns an upper bound estimate of the number of bytes occupied by the serialized message
func (z *TestType) Msgsize() (s int) {
	s = 3 + 6
	if z.F == nil {
		s += msgp.NilSize
	} else {
		s += msgp.Float64Size
	}
	s += 9 + msgp.MapHeaderSize
	if z.Els != nil {
		for za0001, za0002 := range z.Els {
			_ = za0002
			s += msgp.StringPrefixSize + len(za0001) + msgp.StringPrefixSize + len(za0002)
		}
	}
	s += 7 + 1 + 8 + msgp.StringPrefixSize + len(z.Obj.ValueA) + 8 + msgp.BytesPrefixSize + len(z.Obj.ValueB) + 6
	if z.Child == nil {
		s += msgp.NilSize
	} else {
		s += z.Child.Msgsize()
	}
	s += 5 + msgp.TimeSize + 4 + msgp.GuessSize(z.Any) + 9 + z.Appended.Msgsize() + 4 + z.Num.Msgsize() + 5 + msgp.ByteSize + 5 + msgp.Int32Size + 8
	if z.RunePtr == nil {
		s += msgp.NilSize
	} else {
		s += msgp.Int32Size
	}
	s += 11
	if z.RunePtrPtr == nil {
		s += msgp.NilSize
	} else {
		if *z.RunePtrPtr == nil {
			s += msgp.NilSize
		} else {
			s += msgp.Int32Size
		}
	}
	s += 10 + msgp.ArrayHeaderSize + (len(z.RuneSlice) * (msgp.Int32Size)) + 7 + msgp.ArrayHeaderSize
	for za0004 := range z.Slice1 {
		s += msgp.StringPrefixSize + len(z.Slice1[za0004])
	}
	s += 7 + msgp.ArrayHeaderSize
	for za0005 := range z.Slice2 {
		s += msgp.StringPrefixSize + len(z.Slice2[za0005])
	}
	s += 9
	if z.SlicePtr == nil {
		s += msgp.NilSize
	} else {
		s += msgp.ArrayHeaderSize
		for za0006 := range *z.SlicePtr {
			s += msgp.StringPrefixSize + len((*z.SlicePtr)[za0006])
		}
	}
	s += 15 + msgp.MapHeaderSize
	if z.MapStringEmpty != nil {
		for za0007, za0008 := range z.MapStringEmpty {
			_ = za0008
			s += msgp.StringPrefixSize + len(za0007) + 1
		}
	}
	s += 16 + msgp.MapHeaderSize
	if z.MapStringEmpty2 != nil {
		for za0009, za0010 := range z.MapStringEmpty2 {
			_ = za0010
			s += msgp.StringPrefixSize + len(za0009) + 1
		}
	}
	return
}

